// Parse SQLite timestamps (no timezone) as UTC
function parseTs(ts) {
  if (!ts) return new Date(NaN);
  if (ts.includes('Z') || ts.includes('+')) return new Date(ts);
  return new Date(ts.replace(' ', 'T') + 'Z');
}
